<?php ob_start();?><h1>Painel</h1><div class="metrics"><?php foreach($counts as$status=>$count):?><article><span><?=e($status)?></span><strong><?=e($count)?></strong></article><?php endforeach;?></div><section class="card"><h2>Relatórios</h2><?php if(!$reports):?><p class="empty">Nenhum relatório encontrado.</p><?php else:?><div class="table"><table><thead><tr><th>Professor</th><th>Período</th><th>Turma</th><th>Disciplina</th><th>Status</th><th>Prazo</th><th>Ação</th></tr></thead><tbody><?php foreach($reports as$r):?><tr><td><?=e($r['professor_nome']??$_SESSION['user']['nome'])?></td><td><?=e($r['periodo'])?></td><td><?=e($r['turma_nome_snapshot'])?></td><td><?=e($r['disciplina'])?></td><td><span class="badge status-<?=e(strtolower($r['status']))?>"><?=e($r['status'])?></span></td><td><?=e($r['data_fim'])?></td><td><a class="button" href="/relatorios/<?=e($r['id'])?>">Abrir</a></td></tr><?php endforeach;?></tbody></table></div><?php endif;?></section><?php $content=ob_get_clean();require __DIR__.'/layout.php';
